#include <stdio.h>
#include <string.h>

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        char word[101]; int end;
        scanf("%s", word);
        scanf("%d", &end);
        int len = strlen(word);
        if(end > len) end = len;
        printf("[");
        for(int i=0;i<end;i++){
            printf("'%c'", word[i]);
            if(i != end-1) printf(", ");
        }
        printf("]\n");
    }
    return 0;
}

