import sys

def main():
    data = sys.stdin.read().splitlines()
    if not data:
        return
    t = int(data[0].strip())
    idx = 1
    out = []
    for _ in range(t):
        word = data[idx]
        idx += 1
        end = int(data[idx].strip())
        idx += 1
        if end > len(word):
            end = len(word)
        selected = list(word[:end])
        out.append(str(selected))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    main()

